{% assign current_variant = product.selected_or_first_available_variant %}
{% assign product_price = current_variant.price %}
{% assign compare_price = current_variant.compare_at_price %}

<div class="nm-price-block">
  {% if compare_price > product_price %}
    <span class="nm-price-old">{{ compare_price | money }}</span>
    <span class="nm-price-new">{{ product_price | money }}</span>
  {% else %}
    <span class="nm-price-normal">{{ product_price | money }}</span>
  {% endif %}
</div>

<style>
  .nm-price-block {
    display: flex;
    align-items: center;
    gap: 16px;
    flex-wrap: wrap;
    font-family: inherit;
    line-height: 1;
  }

  .nm-price-old {
    font-size: 18px;
    font-weight: 400;
    color: #111111;
    text-decoration: line-through;
  }

  .nm-price-new {
    font-size: 18px;
    font-weight: 700;
    color: #c00000;
  }

  .nm-price-normal {
    font-size: 18px;
    font-weight: 700;
    color: #111111;
  }
</style>
